import numpy as np

def cosine(a, b):
    return a @ b / (np.linalg.norm(a) * np.linalg.norm(b))

query = np.array([0.9, 0.1, 0.0])
docs  = {"recovery": [0.85, 0.15, 0.0], "weather": [0.0, 0.1, 0.95]}

best = max(docs, key=lambda d: cosine(query, np.array(docs[d])))
print(best)   # 'recovery' -> closest by meaning

def safe_compare(vec_a, vec_b, model_a, model_b):
    assert model_a == model_b, "different models -> meaningless"
    assert vec_a.shape == vec_b.shape, "dimension mismatch"
    a = vec_a / (np.linalg.norm(vec_a) + 1e-9)
    b = vec_b / (np.linalg.norm(vec_b) + 1e-9)
    return float(a @ b)
